import axios from "axios";
import { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import { useAuth } from "../context/AuthContext";
import { useProgress } from "../context/ProgressContext";

const SECTION_LABELS = {
  vocabulary: "Vocabulary",
  phrases: "Phrases",
  sentences: "Sentences",
  quiz: "Quiz",
  story: "Story",
  listening: "Listening",
  speaking: "Speaking",
  conversation: "Conversation",
};

const SECTION_ICONS = {
  vocabulary: "📝",
  phrases: "💬",
  sentences: "✍️",
  quiz: "🧩",
  story: "📖",
  listening: "🎧",
  speaking: "🎤",
  conversation: "🤝",
};

const LEVEL_NAMES = ["Beginner", "Elementary", "Intermediate", "Upper-Intermediate", "Advanced"];
const LEVEL_EMOJIS = ["🌱", "📖", "🗣️", "📡", "🏆"];
const LEVEL_COLORS = [
  { bg: "rgba(29,158,117,.12)", border: "rgba(29,158,117,.3)", text: "#1D9E75" },
  { bg: "rgba(55,138,221,.12)", border: "rgba(55,138,221,.3)", text: "#378ADD" },
  { bg: "rgba(127,119,221,.12)", border: "rgba(127,119,221,.3)", text: "#7F77DD" },
  { bg: "rgba(186,117,23,.12)", border: "rgba(186,117,23,.3)", text: "#BA7517" },
  { bg: "rgba(212,83,126,.12)", border: "rgba(212,83,126,.3)", text: "#D4537E" },
];

const StatCard = ({ icon, label, value, accent }) => (
  <div
    style={{
      background: "var(--color-background-secondary)",
      border: `0.5px solid var(--color-border-tertiary)`,
      borderRadius: "var(--border-radius-lg)",
      padding: "1rem 1.25rem",
      display: "flex",
      flexDirection: "column",
      gap: 6,
    }}
  >
    <span style={{ fontSize: 20 }}>{icon}</span>
    <span
      style={{
        fontSize: 22,
        fontWeight: 500,
        color: accent || "var(--color-text-primary)",
        lineHeight: 1.2,
      }}
    >
      {value}
    </span>
    <span style={{ fontSize: 12, color: "var(--color-text-secondary)", fontWeight: 500 }}>
      {label}
    </span>
  </div>
);

const SectionPill = ({ label, icon, done }) => (
  <span
    style={{
      display: "inline-flex",
      alignItems: "center",
      gap: 4,
      fontSize: 11,
      fontWeight: 500,
      padding: "3px 8px",
      borderRadius: 999,
      border: "0.5px solid",
      borderColor: done ? "rgba(29,158,117,.4)" : "var(--color-border-tertiary)",
      background: done ? "rgba(29,158,117,.08)" : "var(--color-background-secondary)",
      color: done ? "#0F6E56" : "var(--color-text-tertiary)",
      whiteSpace: "nowrap",
    }}
  >
    {done && <span style={{ fontSize: 9 }}>✓</span>}
    <span style={{ fontSize: 12 }}>{icon}</span>
    {label}
  </span>
);

const LessonCard = ({ p, onNavigate, variant }) => {
  const isCompleted = variant === "completed";
  const done = Object.values(p.completedSections || {}).filter(Boolean).length;
  const pct = Math.round((done / 8) * 100);

  return (
    <div
      style={{
        background: "var(--color-background-primary)",
        border: "0.5px solid var(--color-border-tertiary)",
        borderRadius: "var(--border-radius-lg)",
        padding: "1rem 1.25rem",
        display: "flex",
        flexDirection: "column",
        gap: 10,
      }}
    >
      <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between" }}>
        <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
          <span
            style={{
              fontSize: 11,
              fontWeight: 500,
              padding: "3px 10px",
              borderRadius: 999,
              background: isCompleted ? "rgba(29,158,117,.1)" : "rgba(55,138,221,.1)",
              color: isCompleted ? "#0F6E56" : "#185FA5",
              border: `0.5px solid ${isCompleted ? "rgba(29,158,117,.3)" : "rgba(55,138,221,.3)"}`,
            }}
          >
            {LEVEL_NAMES[p.level]} · Day {p.day}
          </span>
          {p.xpEarned > 0 && (
            <span
              style={{
                fontSize: 11,
                fontWeight: 500,
                color: "#BA7517",
                background: "rgba(186,117,23,.08)",
                border: "0.5px solid rgba(186,117,23,.25)",
                padding: "3px 8px",
                borderRadius: 999,
              }}
            >
              +{p.xpEarned} XP
            </span>
          )}
        </div>
        <button
          onClick={() => onNavigate(`/lesson/${p.level}/${p.day}`)}
          style={{
            fontSize: 12,
            fontWeight: 500,
            color: "var(--color-text-info)",
            background: "none",
            border: "none",
            cursor: "pointer",
            padding: 0,
            whiteSpace: "nowrap",
          }}
        >
          {isCompleted ? "Review →" : "Continue →"}
        </button>
      </div>

      {!isCompleted && (
        <div>
          <div
            style={{
              height: 4,
              background: "var(--color-background-secondary)",
              borderRadius: 99,
              overflow: "hidden",
              marginBottom: 4,
            }}
          >
            <div
              style={{
                height: "100%",
                width: `${pct}%`,
                background: "var(--color-text-info)",
                borderRadius: 99,
                transition: "width .4s ease",
              }}
            />
          </div>
          <span style={{ fontSize: 11, color: "var(--color-text-secondary)" }}>
            {done} of 8 sections · {pct}% complete
          </span>
        </div>
      )}

      <div style={{ display: "flex", flexWrap: "wrap", gap: 5 }}>
        {Object.entries(p.completedSections || {}).map(([k, v]) =>
          isCompleted ? (
            v ? (
              <SectionPill key={k} label={SECTION_LABELS[k]} icon={SECTION_ICONS[k]} done />
            ) : null
          ) : (
            <SectionPill key={k} label={SECTION_LABELS[k]} icon={SECTION_ICONS[k]} done={v} />
          )
        )}
      </div>
    </div>
  );
};

const SectionHeader = ({ icon, title, count }) => (
  <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 12 }}>
    <span style={{ fontSize: 14 }}>{icon}</span>
    <h2
      style={{
        fontSize: 14,
        fontWeight: 500,
        color: "var(--color-text-primary)",
        margin: 0,
      }}
    >
      {title}
    </h2>
    <span
      style={{
        fontSize: 11,
        fontWeight: 500,
        padding: "2px 8px",
        borderRadius: 999,
        background: "var(--color-background-secondary)",
        color: "var(--color-text-secondary)",
        border: "0.5px solid var(--color-border-tertiary)",
      }}
    >
      {count}
    </span>
  </div>
);

const DashboardPage = () => {
  const { user } = useAuth();
  const { allProgress, fetchAllProgress } = useProgress();
  const [stats, setStats] = useState(null);
  const navigate = useNavigate();

  useEffect(() => {
    fetchAllProgress();
    axios
      .get("/api/progress/stats/overview")
      .then((r) => setStats(r.data))
      .catch(() => {});
  }, []);

  const completed = allProgress.filter((p) => p.isCompleted);
  const inProgress = allProgress.filter(
    (p) => !p.isCompleted && Object.values(p.completedSections || {}).some(Boolean)
  );

  const level = user?.currentLevel || 0;
  const levelColor = LEVEL_COLORS[level] || LEVEL_COLORS[0];

  return (
    <div
      style={{
        width: "100%",
        maxWidth: 720,
        margin: "0 auto",
        padding: "0 1rem",
        display: "flex",
        flexDirection: "column",
        gap: "1.75rem",
      }}
    >
      {/* Page header */}
      <div>
        <h1 style={{ fontSize: 22, fontWeight: 500, color: "var(--color-text-primary)", margin: "0 0 4px" }}>
          My progress
        </h1>
        <p style={{ fontSize: 13, color: "var(--color-text-secondary)", margin: 0 }}>
          Track your English learning journey
        </p>
      </div>

      {/* Stats row */}
      <div
        style={{
          display: "grid",
          gridTemplateColumns: "repeat(auto-fit, minmax(130px, 1fr))",
          gap: 10,
        }}
      >
        <StatCard icon="⚡" label="Total XP" value={(user?.totalXP || 0).toLocaleString()} accent="#7F77DD" />
        <StatCard icon="🔥" label="Day streak" value={`${user?.streak || 0} days`} accent="#D85A30" />
        <StatCard icon="✅" label="Completed" value={completed.length} accent="#1D9E75" />
        <StatCard icon="▶️" label="In progress" value={inProgress.length} accent="#378ADD" />
      </div>

      {/* Current level banner */}
      <div
        style={{
          background: levelColor.bg,
          border: `0.5px solid ${levelColor.border}`,
          borderRadius: "var(--border-radius-lg)",
          padding: "1rem 1.25rem",
          display: "flex",
          alignItems: "center",
          gap: 14,
        }}
      >
        <span style={{ fontSize: 32, lineHeight: 1 }}>{LEVEL_EMOJIS[level]}</span>
        <div>
          <p style={{ fontSize: 11, color: "var(--color-text-secondary)", margin: "0 0 2px", fontWeight: 500 }}>
            Current level
          </p>
          <h2 style={{ fontSize: 16, fontWeight: 500, color: "var(--color-text-primary)", margin: "0 0 2px" }}>
            {LEVEL_NAMES[level]}
          </h2>
          <p style={{ fontSize: 12, color: "var(--color-text-secondary)", margin: 0 }}>
            Complete more lessons to level up
          </p>
        </div>
        <div style={{ marginLeft: "auto", display: "flex", gap: 4 }}>
          {LEVEL_NAMES.map((_, i) => (
            <div
              key={i}
              style={{
                width: 6,
                height: 6,
                borderRadius: "50%",
                background: i <= level ? levelColor.text : "var(--color-border-tertiary)",
              }}
            />
          ))}
        </div>
      </div>

      {/* In progress */}
      {inProgress.length > 0 && (
        <div>
          <SectionHeader icon="▶️" title="In progress" count={inProgress.length} />
          <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
            {inProgress.map((p) => (
              <LessonCard key={p._id} p={p} onNavigate={navigate} variant="inProgress" />
            ))}
          </div>
        </div>
      )}

      {/* Completed */}
      {completed.length > 0 && (
        <div>
          <SectionHeader icon="✅" title="Completed lessons" count={completed.length} />
          <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
            {completed.map((p) => (
              <LessonCard key={p._id} p={p} onNavigate={navigate} variant="completed" />
            ))}
          </div>
        </div>
      )}

      {/* Empty state */}
      {allProgress.length === 0 && (
        <div
          style={{
            textAlign: "center",
            padding: "3rem 1rem",
            display: "flex",
            flexDirection: "column",
            alignItems: "center",
            gap: 12,
          }}
        >
          <span style={{ fontSize: 40 }}>📚</span>
          <div>
            <h3 style={{ fontSize: 16, fontWeight: 500, color: "var(--color-text-primary)", margin: "0 0 4px" }}>
              No lessons started yet
            </h3>
            <p style={{ fontSize: 13, color: "var(--color-text-secondary)", margin: 0 }}>
              Start your first lesson to see your progress here
            </p>
          </div>
          <button
            onClick={() => navigate("/")}
            style={{
              marginTop: 8,
              fontSize: 13,
              fontWeight: 500,
              padding: "8px 20px",
              borderRadius: "var(--border-radius-md)",
              border: "0.5px solid var(--color-border-secondary)",
              background: "var(--color-background-secondary)",
              color: "var(--color-text-primary)",
              cursor: "pointer",
            }}
          >
            Go to lessons →
          </button>
        </div>
      )}
    </div>
  );
};

export default DashboardPage;
